mapper.insert:
/* 템플릿 등록 */
INSERT  INTO TB_TMPLAT_INFO
      ( TMPLAT_ID
      , TMPLAT_NM
      , TMPLAT_SE_CODE
      , TMPLAT_COURS
      , USE_AT
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{tmplatId}
        , #{tmplatNm}
        , #{tmplatSeCode}
        , #{tmplatCours}
        , #{useAt}
        , #{frstRegisterId}
        , SYSDATETIME )

mapper.select:
/* 템플릿 목록 조회 (rownum 페이징) */ SELECT * /* TODO: 컬럼 명시 필요 (rownum 페이징 래퍼) */ FROM ( SELECT ROWNUM AS RN , TB.* FROM ( SELECT A.TMPLAT_ID , A.TMPLAT_NM , A.TMPLAT_SE_CODE , A.TMPLAT_COURS , A.USE_AT , A.FRST_REGISTER_ID , A.FRST_REGIST_PNTTM , B.USER_NM AS FRST_REGISTER_NM , C.CODE_NM AS TMPLAT_SE_CODE_NM FROM TB_TMPLAT_INFO A LEFT OUTER JOIN VW_USER_MASTER B ON A.FRST_REGISTER_ID = B.ESNTL_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE C ON A.TMPLAT_SE_CODE = C.CODE WHERE C.CODE_ID = 'COM005'
AND A.TMPLAT_SE_CODE = #{tmplatSeCode}
AND A.TMPLAT_NM LIKE '%' || #{searchWrd} || '%'
AND C.CODE_NM LIKE '%' || #{searchWrd} || '%'
ORDER BY A.FRST_REGIST_PNTTM DESC ) TB ) Z WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

/* 템플릿 목록 총 건수 조회 */ SELECT COUNT(A.TMPLAT_ID) FROM TB_TMPLAT_INFO A LEFT OUTER JOIN VW_USER_MASTER B ON A.FRST_REGISTER_ID = B.ESNTL_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE C ON A.TMPLAT_SE_CODE = C.CODE WHERE C.CODE_ID = 'COM005'
AND A.TMPLAT_SE_CODE = #{tmplatSeCode}
AND A.TMPLAT_NM LIKE '%' || #{searchWrd} || '%'
AND C.CODE_NM LIKE '%' || #{searchWrd} || '%'

mapper.update:
/* 템플릿 수정 */
UPDATE  TB_TMPLAT_INFO
   SET  TMPLAT_SE_CODE  = #{tmplatSeCode}
      , TMPLAT_COURS    = #{tmplatCours}
      , USE_AT          = #{useAt}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = SYSDATETIME
 WHERE  TMPLAT_ID = #{tmplatId}

/* 템플릿 논리 삭제 */
UPDATE  TB_TMPLAT_INFO
   SET  USE_AT          = 'N'
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = SYSDATETIME
 WHERE  TMPLAT_ID = #{tmplatId}
